<script setup lang="ts">
import{computed,nextTick,ref}from'vue';import{onLoad}from'@dcloudio/uni-app';import{medicalApi,type ClinicalNotebook,type ClinicalExamItem,type MedicationGuideRecord,type MedicationGuideContent,type MedicationGuideItem}from'../../api/medical';import{resolveExamStructuredOutput,hasStructuredExamResult,statusLabel,statusTone,sortItemsByAbnormal,resultPayloadEntries,formatPrimaryResultSummary,type SimulatedCheckStructuredOutput,type SimulatedResultItem,type ResultPayloadEntry}from'../../utils/examResult'
interface ExamView{item:ClinicalExamItem;structured:SimulatedCheckStructuredOutput|null;hasStructured:boolean;expanded:boolean;abnormalCount:number;entries:ResultPayloadEntry[];primarySummary:string;brief:string;hasDetail:boolean}
const notebook=ref<ClinicalNotebook|null>(null),loading=ref(true),section=ref('record'),examAnchor=ref(''),registerId=ref(0),expandedExams=ref<Record<number,boolean>>({}),medicationGuide=ref<MedicationGuideRecord|null>(null),medicationGuideLoading=ref(false),medicationGuideExpanded=ref(false)
const diseases=computed(()=>(notebook.value?.diagnosis?.diseases||[]).map(item=>item.diseaseName).filter(Boolean).join('、')||'暂无确诊疾病')
const examViews=computed<ExamView[]>(()=>(notebook.value?.examItems||[]).map(item=>{const structured=resolveExamStructuredOutput(item);const hasStructured=hasStructuredExamResult(item);const resultItems=structured?.resultItems||[];const abnormalCount=resultItems.filter(row=>row.status!=='normal'&&row.status!=='').length;const entries=resultPayloadEntries(item.resultRaw);const primaryKey=item.category==='inspection'?'inspectionResult':'checkResult';const primarySummary=formatPrimaryResultSummary(item.resultRaw,primaryKey);let brief='暂无结果';if(hasStructured&&structured){if(resultItems.length){brief=abnormalCount>0?`异常 ${abnormalCount} 项 / 共 ${resultItems.length} 项`:`${resultItems.length} 项指标均正常`}else if(structured.conclusion){brief=structured.conclusion.length>18?`${structured.conclusion.slice(0,18)}…`:structured.conclusion}}else if(entries.length){brief=`${entries.length} 项记录`}else if(primarySummary){brief=primarySummary.length>18?`${primarySummary.slice(0,18)}…`:primarySummary}const hasDetail=hasStructured||entries.length>0||Boolean(primarySummary);return{item,structured,hasStructured,expanded:Boolean(expandedExams.value[item.id]),abnormalCount,entries,primarySummary,brief,hasDetail}}))
const medicationGuideContent=computed<MedicationGuideContent|null>(()=>{const raw=medicationGuide.value?.guideContent;if(!raw)return null;if(typeof raw==='string'){try{return JSON.parse(raw)as MedicationGuideContent}catch{return null}}return raw as MedicationGuideContent})
const medicationGuideItems=computed<MedicationGuideItem[]>(()=>medicationGuideContent.value?.items||[])
const medicationGuideVisible=computed(()=>{const r=medicationGuide.value;if(!r)return false;if(r.status==='success')return true;if(r.status==='failed')return true;return false})
const medicationGuideFailed=computed(()=>medicationGuide.value?.status==='failed')
function text(value?:unknown,fallback='暂无记录'){if(value===null||value===undefined||String(value).trim()==='')return fallback;return String(value)}
function formatTime(value?:string){return value?value.replace('T',' ').slice(0,16):'—'}
function guideValue(value?:string|null){if(value==null||value===''||value==='null')return'详见药品说明书或咨询药师';return value}
function sortedItems(items:SimulatedResultItem[]){return sortItemsByAbnormal(items||[])}
function toggleExam(id:number){expandedExams.value[id]=!expandedExams.value[id]}
function toggleMedicationGuide(){medicationGuideExpanded.value=!medicationGuideExpanded.value}
function back(){uni.navigateBack({fail:()=>uni.reLaunch({url:'/pages/records/index'})})}
async function load(){loading.value=true;try{notebook.value=await medicalApi.visitNotebook(registerId.value);if(!notebook.value.archived&&notebook.value.message)uni.showToast({title:notebook.value.message,icon:'none'})}finally{loading.value=false}}
async function loadMedicationGuide(){if(!registerId.value)return;medicationGuideLoading.value=true;try{medicationGuide.value=await medicalApi.medicationGuide(registerId.value)}catch{medicationGuide.value=null}finally{medicationGuideLoading.value=false}}
onLoad(async options=>{registerId.value=Number(options?.registerId||0);section.value=String(options?.section||'record');if(!registerId.value){uni.showToast({title:'缺少就诊记录编号',icon:'none'});return}await load();if(section.value==='check')nextTick(()=>examAnchor.value='exam-section');else if(section.value==='prescription')nextTick(()=>examAnchor.value='prescription-section');loadMedicationGuide()})
</script>
<template><view class="detail-page"><view class="header"><view class="back" @tap="back">‹</view><view class="header-title"><text>门诊病历本</text><text>熙康云医院 · 患者查阅版</text></view><view class="medical-mark">+</view></view><scroll-view class="content" scroll-y :scroll-into-view="examAnchor"><view v-if="loading" class="state">正在读取病历…</view><template v-else-if="notebook"><view class="patient-card"><view class="patient-top"><view class="avatar">{{(notebook.header.realName||'患').slice(0,1)}}</view><view><text>{{notebook.header.realName||'患者'}}</text><text>{{notebook.header.gender||'—'}} · {{notebook.header.age!=null?`${notebook.header.age}岁`:'年龄未记录'}}</text></view><text class="archived">✓ 已归档</text></view><view class="meta-grid"><view><text>病历号</text><text>{{notebook.header.caseNumber||registerId}}</text></view><view><text>就诊时间</text><text>{{formatTime(notebook.header.visitDate)}}</text></view><view><text>就诊科室</text><text>{{notebook.header.departmentName||'—'}}</text></view><view><text>接诊医生</text><text>{{notebook.header.physicianName||'—'}}</text></view></view></view><view class="section-card"><view class="section-head"><text class="number">01</text><view><text>病历摘要</text><text>MEDICAL SUMMARY</text></view></view><view class="field-list"><view><text>主诉</text><text>{{text(notebook.medicalSummary.readme)}}</text></view><view><text>现病史</text><text>{{text(notebook.medicalSummary.present)}}</text></view><view><text>既往史</text><text>{{text(notebook.medicalSummary.history)}}</text></view><view><text>过敏史</text><text>{{text(notebook.medicalSummary.allergy,'未记录明确过敏史')}}</text></view><view><text>体格检查</text><text>{{text(notebook.medicalSummary.physique)}}</text></view></view></view><view class="section-card diagnosis-card"><view class="section-head"><text class="number green">02</text><view><text>诊断信息</text><text>DIAGNOSIS</text></view></view><view class="primary-diagnosis"><text>初步诊断</text><text>{{text(notebook.preliminaryDiagnosis,'暂无初步诊断')}}</text></view><view class="diagnosis-grid"><view><text>确诊结论</text><text>{{text(notebook.diagnosis?.diagnosis,'暂无确诊')}}</text></view><view><text>疾病</text><text>{{diseases}}</text></view><view><text>治疗方案</text><text>{{text(notebook.diagnosis?.cure)}}</text></view><view><text>注意事项</text><text>{{text(notebook.diagnosis?.careful)}}</text></view></view></view><view id="exam-section" class="section-card"><view class="section-head"><text class="number purple">03</text><view><text>检查检验</text><text>EXAMINATION & LAB</text></view><text class="count">{{notebook.examItems?.length||0}} 项</text></view><view v-if="notebook.examItems?.length" class="exam-list"><view v-for="view in examViews" :key="view.item.id" class="exam-item" :class="{expanded:view.expanded}"><view class="exam-summary" @tap="view.hasDetail?toggleExam(view.item.id):undefined"><view class="exam-icon" :class="view.item.category">◇</view><view class="exam-summary-info"><text class="exam-summary-name">{{view.item.techName||'检查项目'}}</text><text class="exam-summary-meta">{{view.item.category==='inspection'?'检验项目':'检查项目'}} · {{view.item.state||'状态未知'}}<text v-if="view.item.completedAt"> · {{formatTime(view.item.completedAt)}}</text></text></view><view class="exam-summary-right"><text v-if="view.hasDetail" class="exam-summary-brief" :class="{abnormal:view.abnormalCount>0}">{{view.brief}}</text><text v-if="view.hasDetail" class="exam-toggle">{{view.expanded?'收起':'详情'}}</text></view></view><view v-if="view.hasDetail" v-show="view.expanded" class="structured-result"><template v-if="view.hasStructured&&view.structured"><view v-if="view.structured.conclusion" class="conclusion-block" :class="{abnormal:!view.structured.isNormal}"><text class="block-label">检查结论</text><text class="block-text">{{view.structured.conclusion}}</text></view><view v-if="view.structured.notice" class="notice-block"><text class="block-label">提示</text><text class="block-text">{{view.structured.notice}}</text></view><view v-if="view.structured.resultItems.length" class="metric-header"><text class="metric-title">指标明细</text><text class="metric-count">{{view.structured.resultItems.length}} 项<text v-if="view.abnormalCount>0" class="metric-abnormal"> · 异常 {{view.abnormalCount}}</text></text></view><view v-if="view.structured.resultItems.length" class="metric-table"><view class="metric-row metric-row-head"><text class="col-name">项目</text><text class="col-value">结果</text><text class="col-range">参考范围</text><text class="col-status">状态</text></view><view v-for="(row,ri) in sortedItems(view.structured.resultItems)" :key="ri" class="metric-row" :class="{abnormal:statusTone(row.status)!=='success'&&statusTone(row.status)!=='info'}"><text class="col-name">{{row.itemName||row.itemCode||'—'}}</text><text class="col-value">{{row.value}}{{row.unit?` ${row.unit}`:''}}</text><text class="col-range">{{row.referenceRange||'—'}}</text><view class="col-status"><text class="status-tag" :class="statusTone(row.status)">{{statusLabel(row.status)}}</text></view></view></view></template><template v-else-if="view.entries.length"><view class="entry-list"><view v-for="entry in view.entries" :key="entry.key" class="entry-row"><text class="entry-label">{{entry.label}}</text><text class="entry-value">{{entry.value}}</text></view></view></template><template v-else-if="view.primarySummary"><view class="conclusion-block"><text class="block-label">{{view.item.category==='inspection'?'检验结论':'检查结论'}}</text><text class="block-text">{{view.primarySummary}}</text></view></template><template v-else><view class="result-empty"><text>暂无结果摘要</text></view></template><view v-if="view.item.aiAnalysis" class="ai-block"><view class="ai-block-head"><text class="ai-tag">AI</text><text class="ai-label">AI 指标解读</text></view><view class="ai-block-body">{{view.item.aiAnalysis}}</view></view></view></view></view><view v-else class="empty">本次就诊暂无检查检验项目</view></view><view class="section-card"><view class="section-head"><text class="number orange">04</text><view><text>综合分析</text><text>CLINICAL ANALYSIS</text></view></view><view class="analysis">{{text(notebook.w3Analysis?.overallAnalysis,notebook.w3Analysis?.completed?'暂无综合分析内容':'待医生解读')}}</view></view><view id="prescription-section" class="section-card"><view class="section-head"><text class="number cyan">05</text><view><text>本次处方</text><text>PRESCRIPTION</text></view><text class="count">{{notebook.prescription?.items?.length||0}} 种</text></view><view v-if="notebook.prescription?.items?.length" class="drug-list"><view v-for="(item,index) in notebook.prescription.items" :key="index"><view class="drug-index">{{index+1}}</view><view><text>{{item.drugName||'药品'}}</text><text>{{item.drugUsage||'用法未记录'}}</text></view><text>× {{item.drugNumber||'—'}}</text></view></view><view v-else class="empty">本次就诊暂无处方</view></view><view v-if="medicationGuideVisible" id="medication-guide-section" class="section-card medication-guide-card" :class="{expanded:medicationGuideExpanded}"><view class="section-head" @tap="toggleMedicationGuide"><text class="number teal">06</text><view><text>用药指导</text><text>MEDICATION GUIDE</text></view><text class="count">{{medicationGuideItems.length}} 种</text><text class="mg-toggle">{{medicationGuideExpanded?'收起':'查看'}}</text></view><view v-if="medicationGuideLoading" class="state">正在生成用药指导…</view><template v-else-if="medicationGuideFailed"><view v-if="medicationGuideExpanded" class="mg-empty"><text>用药指导生成失败</text><text class="mg-empty-hint">{{medicationGuide?.errorMessage||'请稍后查看或联系药师'}}</text></view><view v-else class="mg-collapsed-hint failed" @tap="toggleMedicationGuide"><text>用药指导生成失败 · 点击查看详情</text></view></template><template v-else><view v-if="!medicationGuideExpanded" class="mg-collapsed-hint" @tap="toggleMedicationGuide"><text>AI 辅助生成 · 共 {{medicationGuideItems.length}} 种药品</text><text class="mg-collapsed-cta">点击展开 ›</text></view><template v-else><view v-if="medicationGuideContent?.generalAdvice" class="mg-advice"><text class="block-label">用药总提示</text><text class="block-text">{{medicationGuideContent.generalAdvice}}</text></view><view v-if="medicationGuideItems.length" class="mg-drug-list"><view v-for="(item,idx) in medicationGuideItems" :key="idx" class="mg-drug"><view class="mg-drug-head"><text class="mg-drug-idx">{{idx+1}}</text><view class="mg-drug-title"><text class="mg-drug-name">{{item.drugName||'药品'}}</text><text v-if="item.drugFormat" class="mg-drug-spec">{{item.drugFormat}}</text></view><text v-if="item.quantity" class="mg-drug-qty">× {{item.quantity}}</text></view><view class="mg-field-list"><view v-if="item.usageText" class="mg-field"><text class="mg-field-label">医嘱用法</text><text class="mg-field-value">{{guideValue(item.usageText)}}</text></view><view v-if="item.howToTake" class="mg-field"><text class="mg-field-label">服药建议</text><text class="mg-field-value">{{guideValue(item.howToTake)}}</text></view><view v-if="item.takeWithFood" class="mg-field"><text class="mg-field-label">服药时机</text><text class="mg-field-value">{{guideValue(item.takeWithFood)}}</text></view><view v-if="item.precautions" class="mg-field"><text class="mg-field-label">注意事项</text><text class="mg-field-value">{{guideValue(item.precautions)}}</text></view><view v-if="item.sideEffects" class="mg-field"><text class="mg-field-label">可能的不良反应</text><text class="mg-field-value">{{guideValue(item.sideEffects)}}</text></view><view v-if="item.storage" class="mg-field"><text class="mg-field-label">储存条件</text><text class="mg-field-value">{{guideValue(item.storage)}}</text></view></view></view></view><view v-if="medicationGuideContent?.interactionsNote" class="mg-interactions"><text class="block-label">联合用药提示</text><text class="block-text">{{medicationGuideContent.interactionsNote}}</text></view><view class="mg-footer"><text>本指导单由 AI 辅助生成，仅供患者参考；具体用药请以医嘱为准。</text><text>如有不适，请及时联系医生或药师。</text></view></template></template></view><view class="disclaimer">◆ 本页为医生归档的门诊病历资料，仅供患者本人查阅，如有疑问请咨询接诊医生。</view></template></scroll-view></view></template>
